import { test, expect } from '@playwright/test';

test.describe('Booking Flow E2E', () => {
  test('[P0] should open modal from hero and select a timeslot', async ({ page }) => {
    // Intercept API call to provide deterministic data
    await page.route('**/api/actions/getAvailableSlots', async (route) => {
      const json = {
        success: true,
        data: ['10:00 - 13:00', '15:00 - 18:00', '18:00 - 21:00']
      };
      await route.fulfill({ json });
    });

    await page.goto('/');

    // 1. Open Modal
    const bookButton = page.getByRole('button', { name: /INICIAR PROYECTO/i });
    await expect(bookButton).toBeVisible();
    await bookButton.click();

    // 2. Wait for modal content (Calendar + Grid)
    await expect(page.getByText('SELECCIONA UNA FECHA')).toBeVisible();

    // Wait for the calendar to render the first active day (today)
    const todayButton = page.locator('button.rdp-day_today');
    await expect(todayButton).toBeVisible();
    await todayButton.click();

    // 3. Verify deterministic timeslots from mock
    const slot = page.getByRole('button', { name: /10:00 - 13:00, Disponible/i });
    await expect(slot).toBeVisible();

    // 4. Select slot and verify visual state changes
    await slot.click();
    await expect(slot).toHaveAttribute('aria-pressed', 'true');

    // Wait for visual feedback (orange selection) if applicable
    await expect(slot).toHaveClass(/bg-nmd-orange/);

    // 5. Proceed to next step
    const nextButton = page.getByRole('button', { name: /Siguiente/i });
    await expect(nextButton).toBeVisible();
    await nextButton.click();

    // Verify we moved to the next step (Type Selection)
    await expect(page.getByText('TIPO DE SESIÓN')).toBeVisible();
  });
});
